class FilePathContext:
    def __init__(self, path):
        # Accept either a string or an existing context
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    # Simple detection by extension
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def parse_exchange_table_file(f):
    # Expect header: compound\tlower\tupper
    header = f.readline()
    for line in f:
        if line.startswith('#') or not line.strip():
            continue
        parts = line.strip().split('\t')
        if len(parts) != 3:
            continue
        compound, lower, upper = parts[0], parts[1], parts[2]
        if not compound.isalnum():
            continue
        lower, upper = float(lower), float(upper)
        if lower > upper:
            continue
        yield {'compound': compound, 'lower': lower, 'upper': upper}

def parse_exchange_yaml_file(context, f, default_compartment):
    # Minimal YAML-like stub: each line "compound:lower:upper[:compartment]"
    for line in f:
        if line.startswith('#') or not line.strip():
            continue
        parts = line.strip().split(':')
        if len(parts) < 3:
            continue
        compound = parts[0]
        if not compound.isalnum():
            continue
        lower, upper = float(parts[1]), float(parts[2])
        if lower > upper:
            continue
        entry = {
            'compound': compound,
            'lower': lower,
            'upper': upper,
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

class ParseError(Exception):
    pass


def parse_exchange_file(path, default_compartment):
    with open(path, 'rb') as f:
        # Read the first few bytes to check for BOM
        bom = f.read(3)
        if bom == b'\xef\xbb\xbf':  # UTF-8 BOM
            f.seek(0)
        else:
            f.seek(0)
        # Detect format
        format_detected = resolve_format(None, path)
        if format_detected is None:
            # Try to determine format by content
            first_lines = [f.readline().decode('utf-8').strip() for _ in range(5)]
            f.seek(0)  # Reset file pointer
            if any(':' in line for line in first_lines):
                format_detected = 'yaml'
            else:
                format_detected = 'tsv'

        if format_detected == 'tsv':
            return parse_exchange_table_file(f)
        elif format_detected == 'yaml':
            return parse_exchange_yaml_file(FilePathContext(path), f, default_compartment)
        else:
            raise ParseError('Unsupported file format')


